import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import DonatePage from './pages/DonatePage';
import RequestPage from './pages/RequestPage';
import ViewDonations from './pages/ViewDonations';

function App() {
  // Global state: list of all donations (shared across pages)
  const [donations, setDonations] = useState([
    {
      id: 1,
      name: 'Priya Sharma',
      location: 'Sector 22, Chandigarh',
      foodType: 'Cooked Meals',
      quantity: '30 plates',
      contact: '9876543210',
      date: '2025-04-15',
      status: 'Available',
    },
    {
      id: 2,
      name: 'Rajan Mehta',
      location: 'Panchkula, Haryana',
      foodType: 'Packaged Food',
      quantity: '50 packets',
      contact: '9812345678',
      date: '2025-04-16',
      status: 'Available',
    },
    {
      id: 3,
      name: 'Sunita NGO',
      location: 'Phase 7, Mohali',
      foodType: 'Raw Vegetables',
      quantity: '15 kg',
      contact: '9988776655',
      date: '2025-04-17',
      status: 'Available',
    },
  ]);

  const addDonation = (donation) => {
    const newDonation = {
      ...donation,
      id: Date.now(),
      date: new Date().toISOString().split('T')[0],
      status: 'Available',
    };
    setDonations((prev) => [newDonation, ...prev]);
    return newDonation;
  };

  const updateDonationStatus = (id, status) => {
    setDonations((prev) =>
      prev.map((d) => (d.id === id ? { ...d, status } : d))
    );
  };

  return (
    <Router>
      <Navbar />
      <main style={{ minHeight: 'calc(100vh - 72px)' }}>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route
            path="/donate"
            element={<DonatePage addDonation={addDonation} />}
          />
          <Route
            path="/request"
            element={<RequestPage donations={donations} updateDonationStatus={updateDonationStatus} />}
          />
          <Route
            path="/donations"
            element={<ViewDonations donations={donations} updateDonationStatus={updateDonationStatus} />}
          />
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </main>
    </Router>
  );
}

export default App;
